orders = LOAD '/datasets/orders.csv' USING PigStorage(',') AS (order_id:int, user_id:int, product:chararray, quantity:int, price:float, order_date:chararray);

-- COMPLETA: Agrupa por producto
by_product = GROUP orders BY product;

-- COMPLETA: Calcula revenue total
revenues = FOREACH by_product GENERATE group AS product, SUM(orders.quantity * orders.price) AS total_revenue;

-- COMPLETA: Ordena y toma top 5
sorted = ORDER revenues BY total_revenue DESC;
top5 = LIMIT sorted 5;

DUMP top5;

